   357→        { label: '15 dias', value: 1 },
   358→        { label: '30 dias', value: 2 },
   359→        { label: '60 dias', value: 3 },
   360→        { label: '90 dias', value: 4 },
   361→      ],
   362→    }, {
   363→      label: 'Tipos de lançamentos',
   364→      options: [
   365→        { label: 'Ganhos', value: 'CREDIT' },
   366→        { label: 'Usados', value: 'RESCUE' },
   367→        { label: 'Expirados', value: 'EXPIRED' },
   368→      ],
